parameters.jsCode:
// Build the narration text from the daily video script context.
// Concatenates the intro, each segment script, and the outro into a
// single spoken-word narration string suitable for TTS.
//
// Also resolves the TTS provider, model, voice, and language code to use,
// following the same pattern as 06b_generate_images.json.

const ctx = $input.first().json;
const script = ctx.video_script || ctx.script || {};
const topic_slug = ctx.topic_slug;
const date_key = ctx.date_key;

// Build narration text from the structured video script.
// Falls back to a minimal placeholder when the script is absent or
// incomplete so the TTS step can still be validated non-blocking.
const parts = [];
if (script.intro) parts.push(String(script.intro).trim());
if (Array.isArray(script.segments)) {
  script.segments.forEach(seg => {
    if (seg && seg.script) parts.push(String(seg.script).trim());
  });
}
if (script.outro) parts.push(String(script.outro).trim());

const narration_text = parts.join(' ') || `Daily ${topic_slug} briefing for ${date_key}.`;

// Provider and model selection — mirrors 06b_generate_images.js.
// AI_PROVIDER n8n variable selects the active provider.
// Falls back to 'openai' for any unrecognised value.
const provider = ($vars.AI_PROVIDER || 'openai').toLowerCase();
const effective_provider = ['openai', 'google'].includes(provider) ? provider : 'openai';

// Model defaults mirror OPENAI_MODEL_DEFAULTS / GOOGLE_MODEL_DEFAULTS in openaiConfig.js.
const TTS_MODEL_DEFAULTS = {
  openai: $vars.OPENAI_MODEL_TTS || 'gpt-4o-mini-tts',
  google: $vars.GOOGLE_MODEL_TTS || 'en-US-Chirp3-HD-Aoede',
};
const tts_model = TTS_MODEL_DEFAULTS[effective_provider];

// Voice selection.
// Provider-specific variables take precedence over the shared AI_TTS_VOICE.
// Defaults mirror TTS_VOICE_DEFAULTS in openaiConfig.js.
const TTS_VOICE_DEFAULTS = {
  openai: 'alloy',
  google: 'en-US-Chirp3-HD-Aoede',
};
const tts_voice =
  (effective_provider === 'openai'
    ? ($vars.OPENAI_TTS_VOICE || $vars.AI_TTS_VOICE || TTS_VOICE_DEFAULTS.openai)
    : ($vars.GOOGLE_TTS_VOICE || $vars.AI_TTS_VOICE || TTS_VOICE_DEFAULTS.google)
  ).trim() || TTS_VOICE_DEFAULTS[effective_provider];

// Google TTS language code.
// Resolved in priority order:
//   1. GOOGLE_TTS_LANGUAGE_CODE — provider-specific explicit override
//   2. AI_TTS_LANGUAGE_CODE     — shared explicit override
//   3. Derived from the first two BCP-47 segments of the voice name
//      (e.g. 'en-US-Chirp3-HD-Aoede' → 'en-US').
//      Voice names without at least two BCP-47 segments fall back to 'en-US'.
//   4. Hard default 'en-US'
//
// This ensures that overriding GOOGLE_TTS_VOICE to e.g. 'fr-FR-Standard-A'
// automatically resolves the correct languageCode without any extra config.
function deriveLanguageCode(voiceName) {
  if (!voiceName || typeof voiceName !== 'string') return 'en-US';
  const segments = voiceName.split('-');
  if (segments.length >= 2) {
    return `${segments[0]}-${segments[1]}`;
  }
  return 'en-US';
}

const tts_language_code =
  (($vars.GOOGLE_TTS_LANGUAGE_CODE || $vars.AI_TTS_LANGUAGE_CODE || '').trim())
  || deriveLanguageCode(tts_voice);

// Character limit safeguard — most TTS APIs cap around 4096 chars per call.
// Truncate with an ellipsis to avoid hard API errors while keeping the asset
// non-blocking (a warning is attached in the normalize step if truncated).
const MAX_CHARS = 4096;
const truncated = narration_text.length > MAX_CHARS;
const safe_text = truncated ? narration_text.slice(0, MAX_CHARS - 3) + '...' : narration_text;

return [{
  json: {
    ...ctx,
    _tts_text: safe_text,
    _tts_text_truncated: truncated,
    _tts_char_count: safe_text.length,
    _tts_provider: effective_provider,
    _tts_model: tts_model,
    _tts_voice: tts_voice,
    _tts_language_code: tts_language_code,
  }
}];

