parameters.jsCode:
// Normalize the Google Cloud TTS API response to the shared narration asset contract.
// Non-blocking: if the API returned an error or no audioContent, returns ctx with a warning.
// Google Cloud TTS returns: { audioContent: '<base64 encoded MP3>' }

const raw = $input.first().json;
const ctx = $('Build Narration Text').first().json;
const ts = new Date().toISOString();

// Strip internal underscore-prefixed keys from ctx before merging
const { _tts_text, _tts_text_truncated, _tts_char_count, _tts_provider, _tts_model, _tts_voice, _tts_language_code, ...cleanCtx } = ctx;

// Check for HTTP/API errors (continueOnFail passes errors as json)
const apiError = raw?.error || null;
const audioContent = raw?.audioContent || null;

if (apiError || !audioContent) {
  const reason = apiError
    ? `Google TTS API error: ${JSON.stringify(apiError).slice(0, 300)}`
    : `Google TTS returned no audioContent for ${ctx.topic_slug}/${ctx.date_key}`;
  const narration_asset = {
    provider: 'google',
    model: ctx._tts_model,
    voice: ctx._tts_voice,
    format: 'b64_json',
    audio_encoding: 'mp3',
    audio_b64: null,
    char_count: ctx._tts_char_count,
    duration_seconds: null,
    generated_at: ts,
    warning: reason.slice(0, 500),
  };
  return [{ json: { ...cleanCtx, narration_asset } }];
}

const truncationWarning = ctx._tts_text_truncated
  ? `Input text was truncated to 4096 characters (original exceeded limit).`
  : null;

const narration_asset = {
  provider: 'google',
  model: ctx._tts_model,
  voice: ctx._tts_voice,
  format: 'b64_json',
  audio_encoding: 'mp3',
  audio_b64: audioContent,
  char_count: ctx._tts_char_count,
  duration_seconds: null,
  generated_at: ts,
  warning: truncationWarning,
};

return [{ json: { ...cleanCtx, narration_asset } }];

// Normalize the OpenAI /v1/audio/speech binary response to the shared narration asset contract.
// Non-blocking: if the API returned an error, returns ctx with a warning.
// OpenAI returns binary MP3 audio; n8n HTTP Request (response format: file) exposes it
// via $input.first().binary.  We extract the base64-encoded data from the binary item.

const item = $input.first();
const ctx = $('Build Narration Text').first().json;
const ts = new Date().toISOString();

// Strip internal underscore-prefixed keys from ctx before merging
const { _tts_text, _tts_text_truncated, _tts_char_count, _tts_provider, _tts_model, _tts_voice, _tts_language_code, ...cleanCtx } = ctx;

// Check for HTTP/API errors stored in json when continueOnFail is active
const apiError = item?.json?.error || null;

if (apiError) {
  const reason = `OpenAI TTS API error: ${JSON.stringify(apiError).slice(0, 300)}`;
  const narration_asset = {
    provider: 'openai',
    model: ctx._tts_model,
    voice: ctx._tts_voice,
    format: 'b64_json',
    audio_encoding: 'mp3',
    audio_b64: null,
    char_count: ctx._tts_char_count,
    duration_seconds: null,
    generated_at: ts,
    warning: reason.slice(0, 500),
  };
  return [{ json: { ...cleanCtx, narration_asset } }];
}

// Extract base64 audio from the binary item.
// n8n stores binary file responses under $binary with a key matching the
// field name (typically 'data'). The .data property holds the base64 string.
const binaryKey = Object.keys(item.binary || {})[0] || 'data';
const audio_b64 = item?.binary?.[binaryKey]?.data || null;

if (!audio_b64) {
  const reason = `OpenAI TTS returned no binary audio for ${ctx.topic_slug}/${ctx.date_key}`;
  const narration_asset = {
    provider: 'openai',
    model: ctx._tts_model,
    voice: ctx._tts_voice,
    format: 'b64_json',
    audio_encoding: 'mp3',
    audio_b64: null,
    char_count: ctx._tts_char_count,
    duration_seconds: null,
    generated_at: ts,
    warning: reason.slice(0, 500),
  };
  return [{ json: { ...cleanCtx, narration_asset } }];
}

const truncationWarning = ctx._tts_text_truncated
  ? `Input text was truncated to 4096 characters (original exceeded limit).`
  : null;

const narration_asset = {
  provider: 'openai',
  model: ctx._tts_model,
  voice: ctx._tts_voice,
  format: 'b64_json',
  audio_encoding: 'mp3',
  audio_b64,
  char_count: ctx._tts_char_count,
  duration_seconds: null,
  generated_at: ts,
  warning: truncationWarning,
};

return [{ json: { ...cleanCtx, narration_asset } }];

// Validate the normalized narration asset against the shared contract.
// Non-blocking: logs a warning but does not throw, so a failed TTS step
// never blocks the rest of the daily editorial pipeline.

const VALID_PROVIDERS = ['openai', 'google'];
const VALID_FORMATS = ['b64_json'];
const VALID_ENCODINGS = ['mp3', 'opus', 'aac', 'flac', 'wav', 'pcm'];

const ctx = $input.first().json;
const asset = ctx.narration_asset;

const errors = [];

if (!asset || typeof asset !== 'object') {
  errors.push('narration_asset is missing or not an object');
} else {
  if (!VALID_PROVIDERS.includes(asset.provider)) errors.push(`provider "${asset.provider}" is invalid`);
  if (!asset.model || typeof asset.model !== 'string') errors.push('model missing or not a string');
  if (!asset.voice || typeof asset.voice !== 'string') errors.push('voice missing or not a string');
  if (!VALID_FORMATS.includes(asset.format)) errors.push(`format "${asset.format}" is invalid`);
  if (!VALID_ENCODINGS.includes(asset.audio_encoding)) errors.push(`audio_encoding "${asset.audio_encoding}" is invalid`);
  if (!Number.isInteger(asset.char_count) || asset.char_count < 1) errors.push('char_count must be a positive integer');
  if (!asset.generated_at || typeof asset.generated_at !== 'string') errors.push('generated_at missing or not a string');
  if (asset.audio_b64 !== null && asset.audio_b64 !== undefined && typeof asset.audio_b64 !== 'string') {
    errors.push('audio_b64 must be a string or null');
  }
}

if (errors.length > 0) {
  console.warn(
    `Narration asset validation warnings for ${ctx.topic_slug}/${ctx.date_key} (${errors.length}):`,
    errors.join(', ')
  );
  return [{ json: { ...ctx, narration_asset_warnings: errors } }];
}

return [{ json: { ...ctx, narration_asset_warnings: null } }];
